// Generate YouTube SEO description (3-5K chars) + 10 tags via Claude API
var topicArr = $('Fetch Topic').first().json;
var topic = Array.isArray(topicArr) ? topicArr[0] : topicArr;
var projectArr = $('Fetch Project').first().json;
var project = Array.isArray(projectArr) ? projectArr[0] : projectArr;
var topicId = $('Webhook Trigger').first().json.body.topic_id;
var projectId = topic.project_id || project.id;

// CENTRAL INTELLIGENCE RENDERER (migration 028)
// Stage = 'metadata'. Pulls title DNA, thumbnail DNA, recommended_angle,
// audience_questions, revenue context, viability reasoning, etc. from RPC.
var renderedIntelligence = '';
try {
  var intelRes = await fetch($env.SUPABASE_URL + '/rest/v1/rpc/render_project_intelligence', {
    method: 'POST',
    headers: {
      apikey: $env.SUPABASE_ANON_KEY,
      Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({ p_project_id: projectId, p_stage: 'metadata' })
  });
  if (intelRes.ok) renderedIntelligence = await intelRes.json();
} catch (_) {}

var title = topic.seo_title || topic.original_title;
var hook = topic.narrative_hook || '';
var segments = topic.key_segments || '';
var wordCount = topic.word_count || 0;
var sceneCount = topic.scene_count || 0;
var niche = project.niche || '';
var nicheDesc = project.niche_description || '';
var playlist1 = project.playlist1_name || '';
var playlist2 = project.playlist2_name || '';
var playlist3 = project.playlist3_name || '';

var basePrompt = 'You are an expert YouTube SEO strategist and copywriter specializing in long-form documentary content in the "' + niche + '" niche.\n\n'
  + 'Generate a comprehensive YouTube video description and 10 SEO-optimized tags.\n\n'
  + '=== VIDEO INFO ===\n'
  + 'TITLE: "' + title + '"\n'
  + 'NARRATIVE HOOK: "' + hook + '"\n'
  + 'CHAPTER SEGMENTS: "' + segments + '"\n'
  + 'NICHE: "' + nicheDesc + '"\n'
  + 'VIDEO STATS: ~' + wordCount + ' words, ' + sceneCount + ' scenes, ~2 hour documentary\n'
  + 'CHANNEL PLAYLISTS: "' + playlist1 + '", "' + playlist2 + '", "' + playlist3 + '"\n\n'
  + '=== DESCRIPTION FORMAT (3,000-5,000 characters) ===\n\n'
  + 'Structure in this EXACT order:\n\n'
  + '**SECTION 1 - HOOK (200-300 chars)**\n'
  + 'First 200 characters appear in YouTube search results. Write a provocative, curiosity-driving opening. Do NOT start with "In this video". Start with a shocking fact, bold question, or counterintuitive statement.\n\n'
  + '**SECTION 2 - BODY (500-800 chars)**\n'
  + 'What the viewer will discover. Reference specific segments. Build anticipation for the most surprising parts. Use line breaks between paragraphs.\n\n'
  + '**SECTION 3 - CHAPTERS (timestamps)**\n'
  + 'Generate 8-12 YouTube chapter timestamps from the segment descriptions.\n'
  + 'Format: "H:MM:SS Title"\n'
  + 'First chapter MUST be 0:00:00. Space evenly across ~2 hours.\n'
  + 'Chapter titles should be intriguing (e.g., "The $4.7 Billion Lie" not "Chapter 3").\n\n'
  + '**SECTION 4 - KEY TAKEAWAYS (5-7 bullet points)**\n'
  + 'Format each as a specific, actionable insight, not a vague summary.\n\n'
  + '**SECTION 5 - CALL TO ACTION (2-3 sentences)**\n'
  + 'Subscribe prompt. Ask a specific question to drive comments. Mention the playlist.\n\n'
  + '**SECTION 6 - HASHTAGS (3-5)**\n'
  + 'Relevant hashtags at the very end. Format: #TagOne #TagTwo\n\n'
  + '=== RULES ===\n'
  + '- Total description: 3,000-5,000 characters\n'
  + '- Do NOT include links, social media handles, or placeholder text\n'
  + '- Do NOT use generic phrases like "don\'t forget to like and subscribe"\n'
  + '- Write in a voice that matches the documentary tone (serious, investigative, revelatory)\n'
  + '- Use line breaks generously for readability\n\n'
  + '=== TAG RULES ===\n'
  + '1. Generate exactly 10 SEO tags.\n'
  + '2. Mix: 2-3 broad niche tags, 3-4 specific topic tags, 3-4 long-tail search phrases.\n'
  + '3. All lowercase. Each tag 2-5 words. No single-word tags.\n'
  + '4. Include at least 1 tag matching a common YouTube search query verbatim.\n'
  + '5. Include the niche name in at least 2 tags.\n\n'
  + 'CRITICAL: Return ONLY a raw JSON object, no markdown, no code fences. Keys: "description" (string with newlines) and "tags" (array of 10 strings).';

var promptText = (renderedIntelligence ? renderedIntelligence + '\n\n---\n\n' : '') + basePrompt;

// === BEGIN AU OVERLAY (migration 034) — append country sections for AU
if ((topic.country_target || 'GENERAL') === 'AU') {
  try {
    var __cbRes = await fetch($env.SUPABASE_URL + '/rest/v1/rpc/render_country_blocks', {
      method: 'POST',
      headers: { apikey: $env.SUPABASE_ANON_KEY, Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY, 'Content-Type': 'application/json' },
      body: JSON.stringify({ p_country_target: 'AU' })
    });
    if (__cbRes.ok) {
      var __cb = await __cbRes.json();
      var __auAppend = [
        __cb.country_compliance_block || '',
        __cb.country_terminology_block || '',
        __cb.country_calendar_context || '',
        __cb.country_demonetization_constraints || ''
      ].filter(Boolean).join('\n\n');
      if (__auAppend) promptText = promptText + '\n\n=== AU COUNTRY CONTEXT ===\n\n' + __auAppend;
    }
  } catch (_) { /* leave promptText unchanged on RPC failure */ }
}
// === END AU OVERLAY ===

var claudeResp = await fetch('https://api.anthropic.com/v1/messages', {
  method: 'POST',
  headers: {
    'x-api-key': $env.ANTHROPIC_API_KEY,
    'anthropic-version': '2023-06-01',
    'content-type': 'application/json'
  },
  body: JSON.stringify({
    model: 'claude-sonnet-4-20250514',
    max_tokens: 5000,
    messages: [{ role: 'user', content: promptText }]
  })
});

var claudeResult = await claudeResp.json();
if (!claudeResult.content || !claudeResult.content[0]) {
  throw new Error('Claude API error: ' + JSON.stringify(claudeResult).substring(0, 500));
}

var rawText = claudeResult.content[0].text;
console.log('Claude response (first 300 chars): ' + rawText.substring(0, 300));

var metadata;
try {
  metadata = JSON.parse(rawText.trim());
} catch(e1) {
  var cleaned = rawText.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  try {
    metadata = JSON.parse(cleaned);
  } catch(e2) {
    var jsonMatch = rawText.match(/\{[\s\S]*\}/);
    if (!jsonMatch) throw new Error('No JSON found: ' + rawText.substring(0, 200));
    metadata = JSON.parse(jsonMatch[0]);
  }
}

if (!metadata.description) throw new Error('Missing description');
if (!metadata.tags || !Array.isArray(metadata.tags)) throw new Error('Missing or invalid tags');
while (metadata.tags.length < 10) metadata.tags.push(niche.toLowerCase() + ' documentary');

console.log('Description: ' + metadata.description.length + ' chars, Tags: ' + metadata.tags.join(', '));

return [{ json: {
  topic_id: topicId,
  project_id: topic.project_id,
  drive_folder_id: topic.drive_folder_id,
  title: title,
  niche: niche,
  description: metadata.description,
  tags: metadata.tags,
  current_script_metadata: topic.script_metadata
} }];

// Update Supabase with SEO metadata + prepare doc content for Drive upload
var data = $input.first().json;
var topicId = data.topic_id;
var projectId = data.project_id;

var raw = data.current_script_metadata;
var scriptMetadata;
if (typeof raw === 'string') {
  try { scriptMetadata = JSON.parse(raw); } catch(e) { scriptMetadata = {}; }
} else {
  scriptMetadata = raw || {};
}

scriptMetadata.yt_metadata = {
  description: data.description,
  tags: data.tags,
  generated_at: new Date().toISOString()
};

var supabaseHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': 'Bearer ' + $env.SUPABASE_SERVICE_ROLE_KEY,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

// Try PATCH with dedicated columns first, fallback to script_metadata only
var patchResp = await fetch(
  $env.SUPABASE_URL + '/rest/v1/topics?id=eq.' + topicId,
  {
    method: 'PATCH',
    headers: supabaseHeaders,
    body: JSON.stringify({
      yt_description: data.description,
      yt_tags: data.tags,
      script_metadata: scriptMetadata,
      updated_at: new Date().toISOString()
    })
  }
);
if (!patchResp.ok) {
  var errText = await patchResp.text();
  if (errText.includes('yt_description') || errText.includes('yt_tags')) {
    console.log('yt_description/yt_tags columns missing, saving to script_metadata only');
    var fallbackResp = await fetch(
      $env.SUPABASE_URL + '/rest/v1/topics?id=eq.' + topicId,
      {
        method: 'PATCH',
        headers: supabaseHeaders,
        body: JSON.stringify({
          script_metadata: scriptMetadata,
          updated_at: new Date().toISOString()
        })
      }
    );
    if (!fallbackResp.ok) throw new Error('Fallback PATCH failed: ' + fallbackResp.status);
  } else {
    throw new Error('PATCH topics error: ' + patchResp.status + ' ' + errText);
  }
}
console.log('Updated topic ' + topicId + ' metadata');

var logResp = await fetch(
  $env.SUPABASE_URL + '/rest/v1/production_log',
  {
    method: 'POST',
    headers: supabaseHeaders,
    body: JSON.stringify({
      project_id: projectId,
      topic_id: topicId,
      stage: 'metadata',
      action: 'completed',
      details: { description_length: data.description.length, tags: data.tags }
    })
  }
);
if (!logResp.ok) console.error('POST production_log error: ' + logResp.status);

return [{ json: {
  success: true,
  topic_id: topicId,
  project_id: projectId,
  drive_folder_id: data.drive_folder_id,
  title: data.title,
  niche: data.niche,
  description: data.description,
  tags: data.tags
} }];

// Create formatted SEO document as text file for Drive upload
var data = $input.first().json;
var title = data.title || 'Untitled';
var niche = data.niche || '';
var description = data.description || '';
var tags = data.tags || [];

var doc = '======================================================\n'
  + '  SEO METADATA: ' + title + '\n'
  + '  Niche: ' + niche + '\n'
  + '  Generated: ' + new Date().toISOString().split('T')[0] + '\n'
  + '======================================================\n\n'
  + '--- YOUTUBE DESCRIPTION ---\n'
  + '(Copy everything below into YouTube Studio)\n\n'
  + description + '\n\n'
  + '--- SEO TAGS ---\n'
  + '(Copy into YouTube Studio > Tags field)\n\n'
  + tags.join(', ') + '\n\n'
  + '--- INDIVIDUAL TAGS ---\n';

for (var i = 0; i < tags.length; i++) {
  doc += (i + 1) + '. ' + tags[i] + '\n';
}

doc += '\n--- STATS ---\n'
  + 'Description length: ' + description.length + ' characters\n'
  + 'Tag count: ' + tags.length + '\n'
  + 'Search preview (first 200 chars): ' + description.substring(0, 200) + '...\n';

var b64 = Buffer.from(doc, 'utf-8').toString('base64');
var safeName = title.replace(/[^a-zA-Z0-9 ]/g, '').substring(0, 50).trim();
var fileName = 'SEO_Metadata_' + safeName + '.txt';

return [{
  json: {
    filename: fileName,
    drive_folder_id: data.drive_folder_id,
    topic_id: data.topic_id,
    project_id: data.project_id
  },
  binary: {
    data: {
      data: b64,
      mimeType: 'text/plain',
      fileName: fileName
    }
  }
}];
